module RefModule(
   input                clk ,
   input                rst_n,
   input                load,
   input  [7:0]         parallel_in,

   output reg           serial_out 
);
    reg [7:0] obf_shift_reg;

    always@(posedge clk or negedge rst_n)begin
        if(!rst_n) obf_shift_reg <= 8'd0;
        else if(load) obf_shift_reg <= parallel_in;
        else obf_shift_reg <= {obf_shift_reg[6:0], 1'b0};
    end

    always@(posedge clk or negedge rst_n)begin
        if(!rst_n) serial_out <= 1'b0;
        else serial_out <= obf_shift_reg[7];
    end
endmodule
